-- SKINgenius SEED DATA (run after FIXED-SETUP.sql)
-- All inserts use ON CONFLICT for idempotency
-- ============================================

-- ROOT CAUSES
ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, description=EXCLUDED.description, body_system=EXCLUDED.body_system, evidence_level=EXCLUDED.evidence_level;

-- MECHANISMS
ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, description=EXCLUDED.description, pathway_type=EXCLUDED.pathway_type, evidence_level=EXCLUDED.evidence_level;

-- SUPPLEMENTS
ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, dosage=EXCLUDED.dosage, evidence_level=EXCLUDED.evidence_level, benefits=EXCLUDED.benefits, concerns_treated=EXCLUDED.concerns_treated;

-- CAUSE-CONDITION LINKS
ON CONFLICT (root_cause_id, condition_id) DO UPDATE SET relationship=EXCLUDED.relationship, mechanism_summary=EXCLUDED.mechanism_summary, evidence_level=EXCLUDED.evidence_level;
