INSERT INTO public.supplements (id, name, dosage, evidence_level, benefits, concerns_treated) VALUES
('zinc_picolinate_25_30mg','Zinc picolinate','30mg','B',ARRAY['Inhibits 5-alpha reductase, anti-inflammatory; pair with copper 2-3mg'],ARRAY['acne-vulgaris','excess-sebum-enlarged-pores']),
('omega_3_(epa_dha)','Omega-3 (EPA/DHA)','2000mg','B',ARRAY['Anti-inflammatory; reduces PGE2 and LTB4; improves insulin sensitivity'],ARRAY['acne-vulgaris','excess-sebum-enlarged-pores','barrier-dysfunction']),
('vitamin_d3','Vitamin D3','4000 IU','B',ARRAY['Deficiency common in acne; immune modulation; check 25(OH)D levels'],ARRAY['acne-vulgaris']),
('spearmint_tea','Spearmint tea','2 cups daily','B',ARRAY['Anti-androgen properties; 2 cups daily showed reduction in free testosterone'],ARRAY['hormonal-acne']),
('inositol_(myo_inositol)','Inositol (myo-inositol)','As directed','B',ARRAY['Improves insulin sensitivity; especially beneficial for PCOS-related acne'],ARRAY['hormonal-acne']),
('dim_(diindolylmethane)','DIM (diindolylmethane)','As directed','D',ARRAY['Promotes estrogen metabolism toward beneficial 2-hydroxyestrone pathway'],ARRAY['hormonal-acne']),
('probiotics','Probiotics','As directed','D',ARRAY['Support microbiome balance'],ARRAY['fungal-acne','rosacea','psoriasis','perioral-dermatitis','tinea-versicolor']),
('quercetin','Quercetin','As directed','D',ARRAY['Natural mast cell stabilizer; antihistamine properties'],ARRAY['atopic-dermatitis']),
('vitamin_c','Vitamin C','As directed','B',ARRAY['Antioxidant; supports melanin normalization; immune support'],ARRAY['contact-dermatitis','melasma','post-inflammatory-hyperpigmentation','cold-sore']),
('biotin','Biotin','As directed','D',ARRAY['Supports skin health'],ARRAY['seborrheic-dermatitis']),
('curcumin','Curcumin','As directed','B',ARRAY['Anti-inflammatory; Th17 modulation'],ARRAY['psoriasis']),
('oral_tranexamic_acid','Oral tranexamic acid','250mg 2x daily','A',ARRAY['Prescription; significant improvement in melasma'],ARRAY['melasma']),
('polypodium_leucotomos','Polypodium leucotomos','As directed','B',ARRAY['Oral photoprotectant; reduces UV-induced pigmentation'],ARRAY['melasma','solar-lentigines','vitiligo']),
('zinc','Zinc','As directed','B',ARRAY['Anti-inflammatory; supports healing; immune support'],ARRAY['post-inflammatory-hyperpigmentation','folliculitis','cold-sore']),
('vitamin_e','Vitamin E','As directed','B',ARRAY['Antioxidant; supports barrier'],ARRAY['xerosis','barrier-dysfunction']),
